package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Peixe; public class Tubarao extends Peixe implements Nado, Predacao { public Tubarao(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " não emite som vocal audível."); } public void comer() { System.out.println(getNome() + " está comendo carne."); } public void nadar() { System.out.println(getNome() + " está nadando de forma constante."); } public void cacar() { System.out.println(getNome() + " está caçando pelo faro e movimento."); } }
